#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define Sum(a,b) (sum[(i)]-sum[(j)-1])
using namespace std;
const int N=1e5+1;const long long INF=1e18+5;
inline long long read()
{
	long long res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
long long n,m,sum[N],dp[N][201];int Nxt[N][201],deq[N],h,t;
long double K[N];
inline void print(int x,int y)
{
	if(!y)return;print(Nxt[x][y],y-1);printf("%d ",Nxt[x][y]);
}
inline long double Cnt(int a,int b,int j)
{
	if(sum[a]==sum[b])return 1.0*INF;
	return 1.0*(dp[a][j]-sum[a]*sum[a]-dp[b][j]+sum[b]*sum[b])/(sum[a]-sum[b]);
}
int main()
{
	n=read();m=read();//rep(1,n,i)rep(1,m,j)dp[i][j]=-INF;
	rep(1,n,i)sum[i]=sum[i-1]+read();
	rep(1,m,j)
	{
		h=1;deq[t=1]=0;
		rep(1,n,i)
		{
			while(h<t&&K[h+1]>=-sum[i])h++;
			dp[i][j]=dp[Nxt[i][j]=deq[h]][j-1]+1ll*(sum[i]-sum[deq[h]])*sum[deq[h]];
			while(h<t&&K[t]<=Cnt(deq[t],i,j-1))t--;
			K[t+1]=Cnt(deq[t],i,j-1);deq[++t]=i;
		}
	}
//	rep(1,m,j)
//	{
//		rep(1,n,i)printf("%lld ",dp[i][j]);puts("");
//	}
	printf("%lld\n",dp[n][m]);
	print(n,m);
}
